import { NextResponse } from 'next/server';
import { AnalysisResult } from '@/lib/types';
import { mockAnalysisResult } from '@/lib/mock-data';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { transcription, studentId } = body;

    if (!transcription) {
      return NextResponse.json({ error: "Aucune transcription fournie" }, { status: 400 });
    }

    const apiKey = process.env.ANTHROPIC_API_KEY;

    // Fallback: Si pas de cl├® structur├®e ou cl├® example, on renvoie les r├®sultats mock├®s
    if (!apiKey || apiKey === "sk-ant-your-anthropic-key") {
      console.log("Utilisation de l'analyse mock├®e (Anthropic API Key manquante)");
      // D├®lai artificiel
      await new Promise(resolve => setTimeout(resolve, 2000));
      return NextResponse.json<AnalysisResult>({
        ...mockAnalysisResult,
        studentId: studentId || "1",
        date: new Date().toISOString()
      });
    }

    // Appel r├®el ├á l'API Anthropic Claude 3.5 Sonnet
    const prompt = `Voici une transcription textuelle de la lecture ou de l'expression orale d'un ├®l├¿ve :
"${transcription}"

Tu dois analyser ce texte en te basant sur trois axes pour identifier d'├®ventuels marqueurs de troubles d'apprentissage :
1. Phonologie (Dyslexie) : inversions, substitutions, confusions de sons.
2. Morphosyntaxe (Dysphasie) : accords, conjugaisons, structure globale.
3. Fluence (TDAH / Anxi├®t├®) : r├®p├®titions, mots coup├®s, etc.

Renvoie UNIQUEMENT un objet JSON valide avec la structure suivante, aucun autre texte :
{
  "globalRiskLevel": "Sain" | "Risque Mod├®r├®" | "Risque ├ëlev├®",
  "markers": [
    {
      "name": "Dyslexie (Phonologie)",
      "score": number, // pourcentage de risque 0-100
      "details": ["observation 1", "observation 2"] // 0 ├á 3 observations
    },
    {
      "name": "Dysphasie (Morphosyntaxe)",
      "score": number,
      "details": []
    },
    {
      "name": "Fluence / TDAH",
      "score": number,
      "details": []
    },
    {
      "name": "Anxi├®t├® (Prosodie)",
      "score": number,
      "details": []
    }
  ],
  "recommendations": ["reco 1", "reco 2", "reco 3"]
}`;

    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-3-5-sonnet-20240620',
        max_tokens: 1000,
        temperature: 0,
        messages: [
          { role: 'user', content: prompt }
        ]
      })
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error("Erreur Anthropic:", errorText);
      throw new Error("Erreur de l'API Anthropic lors de l'analyse");
    }

    const data = await response.json();
    let analysisOutput;

    try {
      // Extraire le JSON de la r├®ponse de Claude
      const textResponse = data.content[0].text;
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      analysisOutput = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      console.error("Impossible de parser le JSON de Claude:", data.content[0].text);
      throw new Error("R├®ponse d'analyse invalide");
    }

    const result: AnalysisResult = {
      id: `res-${Date.now()}`,
      studentId: studentId || "1",
      date: new Date().toISOString(),
      globalRiskLevel: analysisOutput.globalRiskLevel,
      transcription: transcription,
      markers: analysisOutput.markers,
      recommendations: analysisOutput.recommendations,
    };

    return NextResponse.json<AnalysisResult>(result);

  } catch (error) {
    console.error("Erreur dans '/api/analyze':", error);
    return NextResponse.json({ error: "Erreur interne" }, { status: 500 });
  }
}

"use client";

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import AudioRecorder from '@/components/AudioRecorder';
import { FileText, User } from 'lucide-react';

export default function NewAnalysisPage() {
  const router = useRouter();
  const [selectedStudent, setSelectedStudent] = useState<string>('');
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Mock students list for dropdown
  const students = [
    { id: '1', name: 'Jean Dupont' },
    { id: '2', name: 'Marie Lefebvre' },
    { id: '3', name: 'Thomas Martin' }
  ];

  const handleRecordingComplete = (blob: Blob) => {
    setRecordedBlob(blob);
  };

  const handleAnalyze = async () => {
    if (!recordedBlob || !selectedStudent) return;

    setIsProcessing(true);

    try {
      // Create form data
      const formData = new FormData();
      formData.append('audio', recordedBlob);
      formData.append('studentId', selectedStudent);

      // Step 1: Transcribe
      const transcribeRes = await fetch('/api/transcribe', {
        method: 'POST',
        body: formData,
      });
      const transcribeData = await transcribeRes.json();

      // Step 2: Analyze
      const analyzeRes = await fetch('/api/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          transcription: transcribeData.text,
          studentId: selectedStudent
        })
      });
      const analysisData = await analyzeRes.json();

      // Navigate to results
      router.push(`/results/${analysisData.id}`);

    } catch (error) {
      console.error("Error during analysis flow:", error);
      alert("Une erreur est survenue lors de l'analyse.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div>
        <h2 className="text-3xl font-black tracking-tight">Nouvelle Analyse</h2>
        <p className="text-slate-500 dark:text-slate-400 mt-1">S├®lectionnez un ├®l├¿ve et enregistrez un extrait audio pour l'analyse DYS.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Left Column: Setup */}
        <div className="space-y-6">
          <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-primary/10 shadow-sm">
            <h3 className="flex items-center gap-2 font-bold mb-4">
              <User size={18} className="text-primary" />
              1. S├®lection de l'├®l├¿ve
            </h3>
            <select 
              value={selectedStudent}
              onChange={(e) => setSelectedStudent(e.target.value)}
              className="w-full p-3 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:outline-none focus:ring-2 focus:ring-primary/50"
            >
              <option value="" disabled>Choisir un ├®l├¿ve...</option>
              {students.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
              <option value="new">+ Ajouter un nouvel ├®l├¿ve</option>
            </select>
          </div>

          <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-primary/10 shadow-sm opacity-50">
            <h3 className="flex items-center gap-2 font-bold mb-4">
              <FileText size={18} className="text-primary" />
              2. Texte de r├®f├®rence (Optionnel)
            </h3>
            <p className="text-sm text-slate-500 mb-4">
              Collez le texte que l'├®l├¿ve doit lire pour une analyse comparative (bient├┤t disponible).
            </p>
            <textarea 
              disabled
              placeholder="Texte ├á lire..."
              className="w-full p-3 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 h-24 resize-none"
            />
          </div>
        </div>

        {/* Right Column: Recording */}
        <div>
          <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-primary/10 shadow-sm h-full flex flex-col">
            <h3 className="flex items-center gap-2 font-bold mb-4">
              <span className="flex items-center justify-center size-5 bg-primary text-white rounded-full text-xs">3</span>
              Enregistrement Audio
            </h3>

            <div className="flex-1 flex flex-col justify-center">
              <AudioRecorder 
                onRecordingComplete={handleRecordingComplete} 
                isProcessing={isProcessing}
              />

              {recordedBlob && (
                <div className="mt-6 flex flex-col items-center gap-4">
                  <div className="text-sm text-green-600 font-medium flex items-center gap-2">
                    <span className="material-symbols-outlined text-sm">check_circle</span>
                    Audio captur├® ({Math.round(recordedBlob.size / 1024)} KB)
                  </div>
                  <button
                    onClick={handleAnalyze}
                    disabled={isProcessing || !selectedStudent}
                    className="w-full bg-primary hover:bg-primary-dark text-white p-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all disabled:opacity-50"
                  >
                    {isProcessing ? "Analyse IA en cours..." : "Lancer l'analyse"}
                  </button>
                  {!selectedStudent && (
                    <p className="text-xs text-red-500">Veuillez d'abord s├®lectionner un ├®l├¿ve.</p>
                  )}
                </div>
              )}
            </div>

          </div>
        </div>

      </div>
    </div>
  );
}

