import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Download, ChevronLeft, AlertTriangle } from 'lucide-react';
import RadarChartDisplay from '@/components/RadarChartDisplay';
import { exportToPDF } from '@/lib/export-pdf';
import { mockAnalysisResult, mockStudents } from '@/lib/mock-data';
import { AnalysisResult, Student } from '@/lib/types';

export default function ResultsPage({ params }: { params: { id: string } }) {
  const router = useRouter();
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [student, setStudent] = useState<Student | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    // Dans une vraie app, on ferait un fetch avec params.id
    // Ici on utilise les donn├®es mock├®es pour le prototype
    setData(mockAnalysisResult);
    const s = mockStudents.find(s => s.id === mockAnalysisResult.studentId);
    if(s) setStudent(s);
  }, [params.id]);

  if (!data || !student) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="animate-pulse flex flex-col items-center">
          <div className="size-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
          <p className="mt-4 text-slate-500">Chargement des r├®sultats...</p>
        </div>
      </div>
    );
  }

  const handleExport = async () => {
    setIsExporting(true);
    await exportToPDF('report-content', `Rapport_DYS_${student.firstName}_${student.lastName}`);
    setIsExporting(false);
