                    </div>
                    {marker.details && marker.details.length > 0 && (
                      <ul className="mt-2 space-y-1">
                        {marker.details.map((detail, dIdx) => (
                          <li key={dIdx} className="text-sm text-slate-500 flex items-start gap-2">
                            <span className="mt-1.5 size-1.5 rounded-full bg-slate-300 shrink-0"></span>
                            {detail}
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-100 dark:border-slate-800">
              <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-primary">
                Recommandations IA
              </h3>
              <div className="bg-primary/5 dark:bg-primary/10 rounded-xl p-6 border border-primary/10">
                <ul className="space-y-3">
                  {data.recommendations.map((rec, idx) => (
                    <li key={idx} className="flex gap-3 text-slate-700 dark:text-slate-300">
                      <span className="material-symbols-outlined text-primary text-xl shrink-0">lightbulb</span>
                      <span className="pt-0.5">{rec}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}

