"use client";

import { useState, useRef, useEffect } from 'react';
import { Mic, Square, Play, Loader2 } from 'lucide-react';

interface AudioRecorderProps {
  onRecordingComplete: (blob: Blob) => void;
  isProcessing?: boolean;
}

export default function AudioRecorder({ onRecordingComplete, isProcessing = false }: AudioRecorderProps) {
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [volume, setVolume] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  // Audio context for volume metering
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      stopRecording();
      if (timerRef.current) clearInterval(timerRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Setup audio context for metering
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      analyserRef.current = audioContextRef.current.createAnalyser();
      sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
      sourceRef.current.connect(analyserRef.current);

      analyserRef.current.fftSize = 256;
      const bufferLength = analyserRef.current.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);

      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        const sum = dataArray.reduce((acc, val) => acc + val, 0);
        const average = sum / bufferLength;
        // Normalize volume to 0-100 range
        setVolume(Math.min(100, Math.round((average / 255) * 100 * 2)));
        animationFrameRef.current = requestAnimationFrame(updateVolume);
      };

      updateVolume();

      // Setup media recorder
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        onRecordingComplete(audioBlob);

        // Cleanup stream
        stream.getTracks().forEach(track => track.stop());
        if (audioContextRef.current?.state !== 'closed') {
          audioContextRef.current?.close();
        }
        if (animationFrameRef.current) {
          cancelAnimationFrame(animationFrameRef.current);
        }
        setVolume(0);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingTime(0);

      timerRef.current = setInterval(() => {
        setRecordingTime((prev) => prev + 1);
      }, 1000);

    } catch (error) {
      console.error('Error accessing microphone:', error);
      alert("Impossible d'acc├®der au microphone. Veuillez v├®rifier les permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-200 dark:border-slate-700">

      {/* Visualizer & Timer */}
      <div className="mb-8 flex flex-col items-center">
        <div className="h-24 w-full max-w-xs flex items-center justify-center gap-1 mb-4">
          {isRecording ? (
            Array.from({ length: 15 }).map((_, i) => (
              <div 
                key={i}
                className="w-2 bg-red-500 rounded-full transition-all duration-75"
                style={{ 
                  height: `${Math.max(10, volume * (Math.random() * 0.5 + 0.5))}%`,
                  opacity: i < 3 || i > 11 ? 0.5 : 1
                }}
              />
            ))
          ) : (
            <div className="text-slate-400 dark:text-slate-500 flex flex-col items-center">
              <Mic size={48} className="mb-2 opacity-50" />
              <span className="text-sm">Pr├¬t ├á enregistrer</span>
            </div>
          )}
        </div>

        {isRecording && (
          <div className="text-3xl font-mono font-bold text-slate-800 dark:text-slate-200">
            {formatTime(recordingTime)}
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="flex items-center gap-4">
        {!isRecording ? (
          <button
            onClick={startRecording}
            disabled={isProcessing}
            className="flex items-center gap-2 bg-red-500 hover:bg-red-600 text-white px-8 py-4 rounded-full font-bold text-lg transition-all shadow-lg shadow-red-500/30 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isProcessing ? <Loader2 className="animate-spin" /> : <Mic size={24} />}
            {isProcessing ? "Analyse en cours..." : "D├®marrer l'enregistrement"}
          </button>
        ) : (
          <button
            onClick={stopRecording}
            className="flex items-center gap-2 bg-slate-900 dark:bg-slate-100 hover:bg-slate-800 dark:hover:bg-white text-white dark:text-slate-900 px-8 py-4 rounded-full font-bold text-lg transition-all"
          >
            <Square size={24} className="fill-current" />
            Arr├¬ter
          </button>
        )}
      </div>
    </div>
  );
}

import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

export const exportToPDF = async (elementId: string, filename: string) => {
  const element = document.getElementById(elementId);
  if (!element) {
    console.error(`Element with id ${elementId} not found`);
    return false;
  }

  try {
    // Save original styles
    const originalStyle = element.getAttribute('style');
    const isDark = document.documentElement.className.includes('dark');

    // Force light mode for PDF rendering
    if (isDark) {
      document.documentElement.classList.remove('dark');
    }

    // Canvas generation
    const canvas = await html2canvas(element, {
      scale: 2, // High resolution
      useCORS: true,
      logging: false,
      backgroundColor: '#ffffff'
    });

    // Restore original styles
    if (isDark) {
      document.documentElement.classList.add('dark');
    }

    // PDF generation
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4'
    });

    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    // Add header text
    pdf.setFont("helvetica", "bold");
    pdf.setFontSize(22);
    pdf.setTextColor(25, 127, 230); // Primary color
    pdf.text("Rapport d'Analyse DYS-Detect", 15, 20);

    pdf.setFont("helvetica", "normal");
    pdf.setFontSize(10);
    pdf.setTextColor(100, 100, 100);
    pdf.text(`G├®n├®r├® le: ${new Date().toLocaleDateString('fr-FR')}`, 15, 28);

    // Add captured image
    pdf.addImage(imgData, 'PNG', 10, 35, pdfWidth - 20, pdfHeight * ((pdfWidth - 20) / pdfWidth));

    // Save
    pdf.save(`${filename}-${new Date().toISOString().split('T')[0]}.pdf`);
    return true;
  } catch (error) {
    console.error("Erreur lors de l'export PDF:", error);
    return false;
  }
};
